package extern

import (
	"bufio"
	"fmt"
	"os"
	"sort"
	"strings"

	"github.com/mochilang/mochi-kotlin/metadata"
	"github.com/mochilang/mochi-kotlin/typemap"
)

// Emit writes a shim.mochi file to outputPath.
// The shim contains:
//
//	// Code generated by mochi pkg lock. DO NOT EDIT.
//	// Artifact: <group>:<artifact>@<version>
//	// Wrapper:  kotlin_wrap/<artifact>/libwrap.{so,dylib} (sha256: <hex>)
//	// Metadata: schema-version <N>
//	(blank line)
//	extern type <ExternTypeName>   (one per class)
//	(blank line)
//	extern fn <shimName>(<params>): <returnType> from kotlin "<fqn>"
//	(one per public function, sorted by class then function name)
func Emit(artifact string, version string, wrapperSHA256 [32]byte,
	classes []*metadata.APIObject, outputPath string) error {

	// Load custom lines from existing file if present.
	customLines := make(map[string]bool)
	if _, statErr := os.Stat(outputPath); statErr == nil {
		info, parseErr := ParseShim(outputPath)
		if parseErr == nil {
			for _, l := range info.CustomLines {
				customLines[l] = true
			}
		}
	}

	var sb strings.Builder
	w := bufio.NewWriter(&sb)

	// Header comments.
	fmt.Fprintln(w, "// Code generated by mochi pkg lock. DO NOT EDIT.")
	fmt.Fprintf(w, "// Artifact: %s@%s\n", artifact, version)
	sha256hex := fmt.Sprintf("%x", wrapperSHA256)
	fmt.Fprintf(w, "// Wrapper:  kotlin_wrap/%s/libwrap (sha256: %s)\n", artifact, sha256hex)
	fmt.Fprintln(w, "// Metadata: schema-version 1")
	fmt.Fprintln(w)

	if len(classes) == 0 {
		if err := w.Flush(); err != nil {
			return err
		}
		return os.WriteFile(outputPath, []byte(sb.String()), 0o644)
	}

	// Sort classes by Kind order then ClassName for deterministic output.
	sorted := make([]*metadata.APIObject, len(classes))
	copy(sorted, classes)
	sort.Slice(sorted, func(i, j int) bool {
		if sorted[i].Kind != sorted[j].Kind {
			return sorted[i].Kind < sorted[j].Kind
		}
		return sorted[i].ClassName < sorted[j].ClassName
	})

	// Determine if any class has suspend functions (need Handle type).
	needsHandle := false
	for _, obj := range sorted {
		for _, fn := range obj.Functions {
			if fn.Flags.IsSuspend {
				needsHandle = true
				break
			}
		}
		if needsHandle {
			break
		}
	}

	// extern type declarations.
	if needsHandle {
		fmt.Fprintln(w, "extern type Handle")
	}
	for _, obj := range sorted {
		externName := typemap.ClassToExternName(obj.ClassName)
		fmt.Fprintf(w, "extern type %s\n", externName)
	}
	fmt.Fprintln(w)

	// Collect all shim functions, sorted by class name then function name.
	type shimLine struct {
		classExtern string
		fnName      string
		line        string
	}
	var lines []shimLine

	for _, obj := range sorted {
		externName := typemap.ClassToExternName(obj.ClassName)
		artifactPrefix := sanitizeArtifact(artifact)

		mc, reason := typemap.TranslateClass(obj, nil)
		if reason != typemap.NotRefused {
			continue
		}

		// Object singleton: emit instance() fn.
		if obj.Kind == metadata.ClassKindObject {
			fnName := fmt.Sprintf("%s_instance", typemap.KotlinToMochiName(externName))
			retType := externName
			line := fmt.Sprintf("extern fn %s(): %s from kotlin %q", fnName, retType, obj.ClassName)
			lines = append(lines, shimLine{externName, fnName, line})
		}

		// Constructors.
		for _, mf := range mc.Constructors {
			line := buildFnLine(mf.Name, mf.Params, mf.ReturnType, obj.ClassName, false, "")
			lines = append(lines, shimLine{externName, mf.Name, line})
		}

		// Regular functions.
		for _, fn := range obj.Functions {
			if !fn.Flags.IsPublic {
				continue
			}
			mf, r := typemap.TranslateFunction(fn)
			if r != typemap.NotRefused {
				continue
			}
			mf.Name = typemap.ShimFnName(externName, fn.Name)

			if fn.Flags.IsSuspend {
				// Async pair: _async + _poll
				asyncName := mf.Name + "_async"
				asyncLine := buildFnLine(asyncName, mf.Params, typemap.MochiType{Name: "Handle", IsExtern: true}, obj.ClassName, false, "")
				lines = append(lines, shimLine{externName, asyncName, asyncLine})

				pollName := mf.Name + "_poll"
				pollParams := append([]typemap.MochiParam{{Name: "handle", Type: typemap.MochiType{Name: "Handle", IsExtern: true}}},
					typemap.MochiParam{Name: "out", Type: typemap.MochiType{Name: "*" + mf.ReturnType.String(), IsExtern: true}})
				pollLine := buildFnLine(pollName, pollParams, typemap.MochiType{Name: "bool"}, obj.ClassName, false, "")
				lines = append(lines, shimLine{externName, pollName, pollLine})
			} else {
				line := buildFnLine(mf.Name, mf.Params, mf.ReturnType, obj.ClassName, false, "")
				lines = append(lines, shimLine{externName, mf.Name, line})
			}
		}

		// Property getters.
		for _, mf := range mc.Properties {
			line := buildFnLine(mf.Name, mf.Params, mf.ReturnType, obj.ClassName, false, "")
			lines = append(lines, shimLine{externName, mf.Name, line})
		}

		// Enum entries: emit per-entry constructor fns.
		if obj.Kind == metadata.ClassKindEnumClass {
			for _, entry := range obj.EnumEntries {
				fnName := fmt.Sprintf("%s_%s_%s", artifactPrefix, typemap.KotlinToMochiName(externName), typemap.KotlinToMochiName(entry))
				retType := typemap.MochiType{Name: externName, IsExtern: true}
				line := buildFnLine(fnName, nil, retType, obj.ClassName, false, "")
				lines = append(lines, shimLine{externName, fnName, line})
			}
		}

		// Sealed class: variant discriminant fns.
		if obj.Kind == metadata.ClassKindSealedClass {
			variantFnName := fmt.Sprintf("%s_variant", typemap.KotlinToMochiName(externName))
			variantParams := []typemap.MochiParam{{Name: "r", Type: typemap.MochiType{Name: externName, IsExtern: true}}}
			variantLine := buildFnLine(variantFnName, variantParams, typemap.MochiType{Name: "int"}, obj.ClassName, false, "")
			lines = append(lines, shimLine{externName, variantFnName, variantLine})

			for _, sub := range obj.SealedSubs {
				subName := typemap.ClassToExternName(sub.ClassName)
				isFnName := fmt.Sprintf("%s_is_%s", typemap.KotlinToMochiName(externName), typemap.KotlinToMochiName(subName))
				isParams := []typemap.MochiParam{{Name: "r", Type: typemap.MochiType{Name: externName, IsExtern: true}}}
				isLine := buildFnLine(isFnName, isParams, typemap.MochiType{Name: "bool"}, obj.ClassName, false, "")
				lines = append(lines, shimLine{externName, isFnName, isLine})
			}
		}
	}

	// Sort lines by class then function name.
	sort.Slice(lines, func(i, j int) bool {
		if lines[i].classExtern != lines[j].classExtern {
			return lines[i].classExtern < lines[j].classExtern
		}
		return lines[i].fnName < lines[j].fnName
	})

	// Write generated lines.
	for _, sl := range lines {
		fmt.Fprintln(w, sl.line)
	}

	// Append custom lines (preserved from existing file) after generated lines.
	for customLine := range customLines {
		fmt.Fprintln(w, customLine)
	}

	if err := w.Flush(); err != nil {
		return err
	}
	return os.WriteFile(outputPath, []byte(sb.String()), 0o644)
}

// buildFnLine constructs one "extern fn ..." line.
func buildFnLine(name string, params []typemap.MochiParam, ret typemap.MochiType, fqn string, _ bool, _ string) string {
	var sb strings.Builder
	sb.WriteString("extern fn ")
	sb.WriteString(name)
	sb.WriteByte('(')
	for i, p := range params {
		if i > 0 {
			sb.WriteString(", ")
		}
		sb.WriteString(p.Name)
		sb.WriteString(": ")
		sb.WriteString(p.Type.String())
	}
	sb.WriteByte(')')
	if !ret.IsVoid && ret.Name != "" {
		sb.WriteString(": ")
		sb.WriteString(ret.String())
	}
	sb.WriteString(" from kotlin ")
	fmt.Fprintf(&sb, "%q", fqn)
	return sb.String()
}

// sanitizeArtifact converts an artifact ID to a valid Mochi identifier prefix.
// e.g. "okhttp" -> "okhttp", "my-lib" -> "my_lib"
func sanitizeArtifact(artifact string) string {
	return strings.ReplaceAll(strings.ToLower(artifact), "-", "_")
}
